"""Треугольный сигнал."""from __future__ import annotationsimport numpy as npfrom .base import BaseSignal, _check_below_nyquist, _time_axisclass TriangleSignal(BaseSignal):    name = "Треугольный сигнал"    description = "Периодический треугольник: (2A/π)·arcsin(sin(2π·f·t))."    params_schema = {        "amplitude": {"type": "float", "default": 1.0, "min": 0.0, "max": 1.0e6,                      "label": "Амплитуда", "units": "В"},        "frequency": {"type": "float", "default": 5.0, "min": 1.0e-6, "max": 1.0e6,                      "label": "Частота", "units": "Гц"},        "duration":  {"type": "float", "default": 1.0, "min": 1.0e-6, "max": 3600.0,                      "label": "Длительность", "units": "с"},        "fs":        {"type": "float", "default": 1000.0, "min": 1.0, "max": 1.0e6,                      "label": "Частота дискретизации", "units": "Гц"},    }    def _compute(self, p: dict) -> tuple[np.ndarray, np.ndarray]:        _check_below_nyquist("frequency", p["frequency"], p["fs"])        t = _time_axis(p["duration"], p["fs"])        x = (2.0 * p["amplitude"] / np.pi) * np.arcsin(            np.sin(2.0 * np.pi * p["frequency"] * t)        )        return t, x